window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["d"]={"Dariusz": "<b>Dariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, gdzie miało formę <i>Dārayavahuš</i>, a zostało utworzone z elementów <i>daraya</i> – „posiadać” i <i>vahu</i> – „dobro” (w związku z tym pierwotne znaczenie imienia można objaśnić jako „ten, który jest dobry”) poprzez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δαρείος i następnie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Darius</em>. Było to imię królów perskich. Według innych źródeł imię oznacza „posiadający bogactwa”.", "Dawid": "<b>Dawid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דָּוִד&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego. Wywodzi się od hebrajskiego wieloznacznego słowa oznaczającego 1. <i>ukochany</i> (czytaj Dawid) lub 2. <i>wujek</i> (czytaj dod).", "Damian": "<b>Damian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia bogini Damii czczonej w Epidaurze, od słowa <i>dámios</i>, <i>démios</i>, oznaczającego: „lekarz ludowy” oraz od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δαμάω, oznaczającego: „poskromiciel, pogromca” lub „uzdrowiciel”.", "Daniel": "<b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dominik": "<b>Dominik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>dominicus</i> oznaczającego „Pański”, „należący do Boga”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dominika</a>.", "Dorian": "<b>Dorian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Użył go <a href=\"https://pl.wikipedia.org/wiki/Oscar_Wilde\" target=\"_blank\" rel=\"noopener noreferrer\">Oscar Wilde</a> w swojej powieści <i>The Picture of Dorian Gray</i> (<a href=\"https://pl.wikipedia.org/wiki/Portret_Doriana_Graya\" target=\"_blank\" rel=\"noopener noreferrer\">Portret Doriana Graya</a>). Wywodzi się od nazwy plemienia <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> – <a href=\"https://pl.wikipedia.org/wiki/Dorowie\" target=\"_blank\" rel=\"noopener noreferrer\">Dorów</a>. W greckiej mitologii Dorowie pochodzą od jednego z herosów: <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklesa</a>.", "Dionizy": "<b>Dionizy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>. W niektórych językach jego odpowiednikiem jest forma Denis albo Dennis; oboczną formą jest <a href=\"https://pl.wikipedia.org/wiki/Dionizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizjusz</a>. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dionizja\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizja</a>.", "Donat": "<b>Donat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „darowany przez Boga/bogów” i tym samym mający podobne znaczenie jak <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>. <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">Hagiografia</a> wymienia ponad 35 świętych o tym imieniu.", "Dieter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Dobromir": "<b>Dobromir</b>, <b>Dobromier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło ono oznaczać „obyś był dobry jako twórca/obrońca pokoju”. Imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku, występuje także w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Diter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Dobrosław": "<b>Dobrosław</b>, <b>Dobroslav</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica</a>: Доброслав), <b>Dobrosav</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Добросав) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starosłowiańskie imię męskie</a> złożone z członów <i>Dobro-</i> (dobry) i <i>-sław</i> (sława), oznaczające „tego, który cieszy się dobrą sławą”. Najstarszy znany zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1230\" target=\"_blank\" rel=\"noopener noreferrer\">1230</a> roku. Dobrosław występuje także w licznych innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach słowiańskich</a>, tj. w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ruski\" target=\"_blank\" rel=\"noopener noreferrer\">ruskim</a>. Istniały także odpowiedniki znaczeniowe tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a>, np. imię jednostopniowe <i>Su-śravas-</i> (miej/masz dobrą sławę) lub dwustopniowe, jak <i>Pra</i> + <i>su-śruta</i> „bądź/jest bardzo dobrze sławny”); człon <i>su-</i> oznacza dobrze, dobry.", "Dobiesław": "<b>Dobiesław</b>, <b>Dobosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Dobie-</i> („stosowny, zdatny” albo „waleczny, dzielny”) i <i>-sław</i> („sława”). Imię to mogło oznaczać „cieszący się słuszną sławą”, „słynący z dzielności”.", "Damazy": "<b>Damazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „zdobywać”. Damazy – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>łagodny, oswojony, ujarzmiony</i>.", "Donald": "<b>Donald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> (<i>Dumno</i> + <i>valos</i>; „świat” + „potężny”, „możny”). <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroirlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">Staroirlandzkie</a> <i>Domnall</i> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">gaelicko-szkockie</a> <i>Domhnall</i> oznacza „silny tego świata” lub „władca świata”.", "Dastin": "<b>Dunstan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a>, oznaczające \"ciemny kamień\", złożone z członów <i>dun</i> — \"ciemny\" i <i>stan</i> — \"kamień\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Dunstan\" target=\"_blank\" rel=\"noopener noreferrer\">święty Dunstan</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">Canterbury</a> (X wiek).", "Dezyderiusz": "<b>Dezyderiusz</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dezydery\" target=\"_blank\" rel=\"noopener noreferrer\">Dezydery</a>.", "Dacjan": "<b>Dacjan</b> – występujące w Polsce <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o nieznanej etymologii. Istnienie jednej z nielicznych odnotowanych w historii postaci o tym imieniu nie zostało udowodnione; różne opowieści o świętych podają, iż był to legat rzymski, prześladujący chrześcijan. Był jednak rzymski polityk Dacjan, wpływowy za czasów <a href=\"https://pl.wikipedia.org/wiki/Konstancjusz_II\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancjusza II</a>, <a href=\"https://pl.wikipedia.org/wiki/Konsulowie_rzymscy#Konsulowie_rzymscy_w_IV_w._n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">konsul rzymski</a> w <a href=\"https://pl.wikipedia.org/wiki/358\" target=\"_blank\" rel=\"noopener noreferrer\">358</a> roku.", "Dietmar": "<b>Ditmar</b>, <b>Dietmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>diot</i> \"lud\" oraz <i>mari</i> \"sławny\", mogło oznaczać \"człowieka cieszącego się sławą wśród ludu\". Staropolskim wariantem jest forma Dziećmar.", "Ditmar": "<b>Ditmar</b>, <b>Dietmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>diot</i> \"lud\" oraz <i>mari</i> \"sławny\", mogło oznaczać \"człowieka cieszącego się sławą wśród ludu\". Staropolskim wariantem jest forma Dziećmar.", "Darosław": "<b>Darosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie powstałe prawdopodobnie jako neologizm na wzór <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a>, może oznaczać&#160;: \"ten, któremu darowana jest sława\".", "Dobromił": "<b>Dobromił</b> – męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dobromi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Dobromiła</a>, nienotowany w źródłach staropolskich.", "Data": "<b>Data</b> – umowne oznaczenie <a href=\"https://pl.wikipedia.org/wiki/Dzie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dnia</a>, <a href=\"https://pl.wikipedia.org/wiki/Miesi%C4%85c\" target=\"_blank\" rel=\"noopener noreferrer\">miesiąca</a> i <a href=\"https://pl.wikipedia.org/wiki/Rok\" target=\"_blank\" rel=\"noopener noreferrer\">roku</a>, służy do zapisu kolejnych dni (<a href=\"https://pl.wikipedia.org/wiki/Doba\" target=\"_blank\" rel=\"noopener noreferrer\">dób</a>) w <a href=\"https://pl.wikipedia.org/wiki/Kalendarz\" target=\"_blank\" rel=\"noopener noreferrer\">kalendarzu</a>, a przez to m.in. do oznaczania ważnych wydarzeń historycznych.", "Dalibor": "<b>Dalebor</b>, <b>Dalibor</b>, <b>Dalibór</b>, <b>Dalbor</b>, <b>Daleborz</b> – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> (\"daleko\", może też \"oddalać\") i <i>-bor</i> (\"walka\"). Oznaczałoby więc \"tego, który pozostaje daleko od walki\" bądź \"tego, który walczy daleko\". Obecnie używane głównie na terenie Bałkanów.", "Dipendra": "<b>Dipendra Bir Bikram Shah Dev</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/27_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">27 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1971\" target=\"_blank\" rel=\"noopener noreferrer\">1971</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/4_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">4 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/2001\" target=\"_blank\" rel=\"noopener noreferrer\">2001</a>) – formalny <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lowie_Nepalu\" target=\"_blank\" rel=\"noopener noreferrer\">król</a> <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepalu</a> przez ostatnie trzy dni życia, sprawca <a href=\"https://pl.wikipedia.org/wiki/Masakra_rodziny_kr%C3%B3lewskiej_w_Nepalu\" target=\"_blank\" rel=\"noopener noreferrer\">masakry rodziny królewskiej</a> <a href=\"https://pl.wikipedia.org/wiki/1_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">1 czerwca</a> 2001.", "Dezydery": "<b>Dezydery</b>, również: <b><a href=\"https://pl.wikipedia.org/wiki/Dezyderiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderiusz</a></b> lub <b>Dezyder</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>desiderius</i> oznaczającego „upragniony”. Imię to jest obecne w Polsce od XIII w. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Dezydery_z_Bourges\" target=\"_blank\" rel=\"noopener noreferrer\">św. Dezydery</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Bourges\" target=\"_blank\" rel=\"noopener noreferrer\">Bourges</a>.", "Duszan": "<b>Duszan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, wywodzące się od słów: dusza, duch. Używane głównie w <a href=\"https://pl.wikipedia.org/wiki/Czechy\" target=\"_blank\" rel=\"noopener noreferrer\">Czechach</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a> oraz <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>.", "Durga": "<b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Demetriusz": "<b>Demetriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w kręgu kultury zachodnioeuropejskiej podległe następnie latynizacji. Wywodzi się od słowa oznaczającego „należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>”, odpowiada też znaczeniu „zajmujący się rolnictwem”. Odpowiednikiem tego imienia, rozpowszechnionym w językach południowo- i wschodniosłowiańskich, jest <i>Dymitr:</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Дми́трий (Dmitrij), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ukrai%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ukr.</a>&#160;Дмитро́ (Dmytro), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bia%C5%82oruski\" target=\"_blank\" rel=\"noopener noreferrer\">biał.</a>&#160;Зьмíцер/Дзмíтры (Źmicier/Dźmitry). Do Polski dwiema drogami to imię dotarło z Zachodu w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Demetrius</em>, Demytrysz, Demetrysz, i ze Wschodu w ruskiej formie Dymitr, Demitr, Dymets, Dmitro.", "Dagobert": "<b>Dagobert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z połączenia słów <i>degr</i> - \"dzień\" i <i>beracht</i> \"jasny\". Istnieje teoria, jakoby Dagobert był imieniem chrzestnym <a href=\"https://pl.wikipedia.org/wiki/Mieszko_I\" target=\"_blank\" rel=\"noopener noreferrer\">Mieszka I</a>.", "Dyzma": "<b>Dyzma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δυσμη (dysmai, dysme) – zachód słońca lub gwiazd, „narodzony o zachodzie”. Imię to przypisywane jest tradycyjnie <a href=\"https://pl.wikipedia.org/wiki/Dobry_%C5%81otr\" target=\"_blank\" rel=\"noopener noreferrer\">dobremu łotrowi</a> – ukrzyżowanemu obok Chrystusa przestępcy, który nawrócił się i dostał obietnicę zbawienia.", "Danisz": "<b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dacjusz": "<b>Dacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Imię Dacjusz, podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Dacjan\" target=\"_blank\" rel=\"noopener noreferrer\">Dacjan</a>, oznacza pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/Dacja\" target=\"_blank\" rel=\"noopener noreferrer\">Dacji</a>.", "Delfin": "Delfin śpi, unosząc się w wodzie na głębokości około 50 cm, z jednym okiem otwartym. Oddycha wynurzając się co 30 sek. na powierzchnię, nie budząc się. Delfiny często polują ławicami. Czasami nawet polują z <a href=\"https://pl.wikipedia.org/wiki/Rekiny\" target=\"_blank\" rel=\"noopener noreferrer\">rekinami</a>. Żywią się <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">rybami</a>, <a href=\"https://pl.wikipedia.org/wiki/Ka%C5%82amarnice\" target=\"_blank\" rel=\"noopener noreferrer\">kalmarami</a> i <a href=\"https://pl.wikipedia.org/wiki/Skorupiaki\" target=\"_blank\" rel=\"noopener noreferrer\">skorupiakami</a>. Ich głównym naturalnym wrogiem jest <a href=\"https://pl.wikipedia.org/wiki/Orka_oceaniczna\" target=\"_blank\" rel=\"noopener noreferrer\">orka</a>. Ich duże rozmiary oznaczają, że mają lepszą ochronę przed zimnem mroźnych mórz.", "Dzierżysław": "<b>Dzierżysław</b>, <b>Dzirżysław</b>, <b>Dziersław</b>, <b>Dzirsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dzierży-</i> („trzymać”) i <i>-sław</i> („sława”). Oznaczało prawdopodobnie „tego, który posiada sławę”. Poświadczone w piśmiennictwie od XIII wieku.", "Daisuke": "<b>Daisuke</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいすけ, ダイスケ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Dane": "<b>Dane</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>data</em>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>datum</em>) – zbiory wartości, które przekazują informacje, opisując ilość, jakość, fakt, statystyki, inne znaczenia lub sekwencje symboli, które mogą być dalej interpretowane i przetwarzane.", "Danu": "Danu może być identyfikowana z indoeuropejską boginią wody <b>Danavas</b>, uznawaną za pramatkę - bóstwo najbardziej pierwotne, wywodzące się z okresu matriarchatu. O powiązaniach Danu z wodą mówią nazwy wielkich europejskich rzek: <a href=\"https://pl.wikipedia.org/wiki/Don\" target=\"_blank\" rel=\"noopener noreferrer\">Donu</a>, <a href=\"https://pl.wikipedia.org/wiki/Dniestr\" target=\"_blank\" rel=\"noopener noreferrer\">Dniestru</a>, <a href=\"https://pl.wikipedia.org/wiki/Dniepr\" target=\"_blank\" rel=\"noopener noreferrer\">Dniepru</a>, a zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/Dunaj\" target=\"_blank\" rel=\"noopener noreferrer\">Dunaju</a> (łac. Danubius), który Celtowie czcili szczególnie. Na jej cześć zatapiali w rzekach i jeziorach kotły ofiarne, możliwe także iż wiele ofiar z ludzi znajdowanych na bagnach w całej Europie było przeznaczone dla niej", "Donard": "Oryginalna nazwa wsi <i>Dún Ard</i> w wolnym tłumaczeniu na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">język polski</a> oznacza \"wysoki fort\" i pochodzi od ruin budowli <i>High Fort</i>, znajdujących się na pobliskim wzgórzu. Dawniej używana była nazwa Dunard.", "Darcy": "<b>Darcy</b> (skrót: D) – niestandardowa <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostka</a> <a href=\"https://pl.wikipedia.org/wiki/Przepuszczalno%C5%9B%C4%87_(hydrodynamika)\" target=\"_blank\" rel=\"noopener noreferrer\">przepuszczalności</a> ośrodków porowatych, powszechnie stosowana w przemyśle <a href=\"https://pl.wikipedia.org/wiki/Ropa_naftowa\" target=\"_blank\" rel=\"noopener noreferrer\">naftowym</a> i <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologii</a>. Jej odpowiednikiem w standardowym układzie jednostek (<a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">SI</a>) jest <a href=\"https://pl.wikipedia.org/wiki/Metr_kwadratowy\" target=\"_blank\" rel=\"noopener noreferrer\">metr kwadratowy</a> (m²).", "Doroteusz": "<b>Doroteusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, oznaczające „dar od boga”; jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dorota\" target=\"_blank\" rel=\"noopener noreferrer\">Dorota</a>. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <b><a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a></b>.", "Domagoj": "<b>Domagoj</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członu <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”) i <i>goj</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*gojiti</i> – „powodować, że żyje; leczyć, uzdrawiać”). Używane w <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a> i nienotowane w Polsce.", "Dzierżykraj": "<b>Dzierżykraj</b>, <b>Dzirżykraj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dzirży-</i> („trzymać”) i <i>-kraj</i> („kraj”). Oznaczało prawdopodobnie „tego, który panuje nad krajem”, „nad okolicą”.", "Daiki": "<b>Daiki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいき, ダイキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Diomedes": "<b>Diomedes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"wymyślony przez <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>\", złożone z członów <i>Dios</i> (Διος) o znaczeniu \"Zeusa\" i <i>medomai</i> (μηδομαι) – \"myśleć\". Jest to imię postaci z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>, a w Kościele katolickim patronem tego imienia jest św. Diomedes, zm. w <a href=\"https://pl.wikipedia.org/wiki/305\" target=\"_blank\" rel=\"noopener noreferrer\">305</a> roku (i inni święci).", "Dobiegniew": "<b>Dobiegniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobie-</i> (\"stosowny, zdatny\", \"waleczny, dzielny\") oraz <i>-gniew</i>. Mogło oznaczać \"ten, którego gniew jest zawsze proporcjonalny do sytuacji\".", "Dżemil": "<b>Dżemil</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> جميل) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>, oznacza „piękny”.", "Dewa": "<b>Dewa</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a> देव, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>deva</i>, „świetlisty”, „jaśniejący”, „oświecony”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Deva; w innych językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tybetański</a> <i>lha</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <i><a href=\"https://pl.wikipedia.org/wiki/Tian\" target=\"_blank\" rel=\"noopener noreferrer\">tiān</a></i> (天), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">koreański</a> <i>chǒn</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> <i>ten</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_wietnamski\" target=\"_blank\" rel=\"noopener noreferrer\">wiet.</a> <i>thiên</i>) – nieposiadająca ciała fizycznego istota nadprzyrodzona, bóg lub <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półbóg</a>, występujący w <a href=\"https://pl.wikipedia.org/wiki/Religie_dharmiczne\" target=\"_blank\" rel=\"noopener noreferrer\">religiach dharmicznych</a> i mitach kultur <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatyckich</a>. Żeńskim odpowiednikiem dewy jest <b><a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a></b>.", "Dyter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Drogomir": "<b>Drogomir</b>, <b>Drogmir</b>, <b>Dragomir</b>, <b>Drahomir</b>, <b>Drohomir</b>, <b>Dargomier</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ten, któremu drogi jest pokój\". Żeńskim odpowiednikiem tych imion jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Drogomira\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomira</a>.", "Dalimir": "<b>Dalemir</b>, <b>Dalimir</b>, <b>Dalemiar</b>, <b>Dalimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> („daleko”, może też „oddalać”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „tego, który rozciąga pokój daleko”. Wystąpiło od XIII wieku.", "Daichi": "<b>Daichi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいち, ダイチ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Daria": "<b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Doctor": "Do dzisiaj największą zagadką jest imię Doktora. Twórcy pierwszy raz ujawnili je w 1979 roku w historii The Armageddon Factor, a brzmiało ono Theta Sigma. Po latach zostało jednak ujawnione, że był to jedynie jego pseudonim z czasów, gdy uczęszczał do akademii Władców Czasu.", "Dobrogniew": "<b>Dobrzegniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dobrze-</i> („dobry”) oraz <i>-gniew</i> („gniew”). Mogło oznaczać „ten, którego gniew jest zawsze dobry” lub in.", "Drogosław": "<b>Drogosław</b>, <b>Dargosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Drogo-</i> („drogi”) i <i>-sław</i> („sława”). Mogło ono oznaczać „człowiek drogiej sławy”. W polskich źródłach występuje od XII wieku.", "Dobrogost": "<b>Dobrogost</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Składa się z członu <i>Dobro-</i> („dobry”) i <i>-gost</i> („gościć”, „gość”). Mogło oznaczać \"dobry, życzliwy dla gości\". Odpowiednik tego imienia, <i>Dobrohost</i>, występuje w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ruski\" target=\"_blank\" rel=\"noopener noreferrer\">ruskim</a>.", "Dalemir": "<b>Dalemir</b>, <b>Dalimir</b>, <b>Dalemiar</b>, <b>Dalimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> („daleko”, może też „oddalać”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „tego, który rozciąga pokój daleko”. Wystąpiło od XIII wieku.", "Dżamil": "<b>Dżamil</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>جميل</b> (pełne imię: <b>Dżamil Ibn Abd Allah Ibn Mamar al-Uzri</b>) (ur. ok. 660 w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Medyna_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Medyny</a>, zm. 701 w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>) – poeta <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabski</a> okresu <a href=\"https://pl.wikipedia.org/wiki/Umajjadzi\" target=\"_blank\" rel=\"noopener noreferrer\">umajjadzkiego</a>, najsłynniejszy przedstawiciel poezji uzryckiej.", "Dżafar": "<b>Dżafar</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab</a>. جعفر) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, oznacza „strumień”.", "Dominika": "<b>Dominika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dominik\" target=\"_blank\" rel=\"noopener noreferrer\">Dominik</a>. Imię łacińskie oznacza dosłownie <i>należącą do Pana</i>, ale pochodzi od określenia <a href=\"https://pl.wikipedia.org/wiki/Niedziela\" target=\"_blank\" rel=\"noopener noreferrer\">niedzieli</a>, zwanej dniem pańskim. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Dominika</a>, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Nikomedia\" target=\"_blank\" rel=\"noopener noreferrer\">Nikomedii</a>.", "Dagan": "<b>Dagan</b>, hebrajski <b>Dagon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דגון&#8206;) – główny bóg czczony przez północno-zachodnie <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">ludy semickie</a>. Prawdopodobnie opiekował się on rolnictwem i zbożem. Był czczony na całym <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> z <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamią</a> włącznie (czcili go m.in. <a href=\"https://pl.wikipedia.org/wiki/Fenicja\" target=\"_blank\" rel=\"noopener noreferrer\">Fenicjanie</a>, <a href=\"https://pl.wikipedia.org/wiki/Amoryci\" target=\"_blank\" rel=\"noopener noreferrer\">Amoryci</a>). Pierwotne znaczenie imienia nie jest znane. Słowo <i>dagán</i> w języku hebrajskim i ugaryckim określa „ziarno” a słowo <i>dag</i> oznacza „rybę”. Według jednego z przekazów bóg Dagan był wynalazcą <a href=\"https://pl.wikipedia.org/wiki/P%C5%82ug\" target=\"_blank\" rel=\"noopener noreferrer\">pługa</a>.", "Dalegor": "<b>Dalegor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Dale-</i> (\"daleki, odległy\"; może też \"oddalać, odsuwać\") i <i>-gor</i> (\"goreć, palić się\"). Mogło oznaczać \"tego, który oddala pożogę\".", "Dąb": "Rodzaj ma duże znaczenie użytkowe. Wiele gatunków dostarcza cenionego <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_szypu%C5%82kowy\" target=\"_blank\" rel=\"noopener noreferrer\">dąb szypułkowy</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_wielkoowocowy\" target=\"_blank\" rel=\"noopener noreferrer\">wielkoowocowy</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_bia%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">biały</a> i <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_czerwony\" target=\"_blank\" rel=\"noopener noreferrer\">czerwony</a>). Kora dębów jest źródłem <a href=\"https://pl.wikipedia.org/wiki/Taniny\" target=\"_blank\" rel=\"noopener noreferrer\">tanin</a>, a kora <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_korkowy\" target=\"_blank\" rel=\"noopener noreferrer\">dębu korkowego</a> – <a href=\"https://pl.wikipedia.org/wiki/Korek_(surowiec)\" target=\"_blank\" rel=\"noopener noreferrer\">korka</a>. Żołędziami karmiono <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awinia_domowa\" target=\"_blank\" rel=\"noopener noreferrer\">świnie</a> i służyły jako pożywienie ludziom. Z <a href=\"https://pl.wikipedia.org/wiki/Galas\" target=\"_blank\" rel=\"noopener noreferrer\">galasów</a> rozwijających się na dębach i ich kory uzyskiwano barwniki. Liczne gatunki uprawiane są jako rośliny ozdobne.", "Dymitriusz": "<b>Demetriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w kręgu kultury zachodnioeuropejskiej podległe następnie latynizacji. Wywodzi się od słowa oznaczającego „należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>”, odpowiada też znaczeniu „zajmujący się rolnictwem”. Odpowiednikiem tego imienia, rozpowszechnionym w językach południowo- i wschodniosłowiańskich, jest <i>Dymitr:</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Дми́трий (Dmitrij), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ukrai%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ukr.</a>&#160;Дмитро́ (Dmytro), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bia%C5%82oruski\" target=\"_blank\" rel=\"noopener noreferrer\">biał.</a>&#160;Зьмíцер/Дзмíтры (Źmicier/Dźmitry). Do Polski dwiema drogami to imię dotarło z Zachodu w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Demetrius</em>, Demytrysz, Demetrysz, i ze Wschodu w ruskiej formie Dymitr, Demitr, Dymets, Dmitro.", "Diogenes": "<b>Diogenes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się z połączenia słów <i>Dios</i> - \"Bóg\" i <i>genes</i> - \"urodzony\", oznaczającego \"urodzony z Boga\".", "D": "<b>D</b> (wymowa: <i>de</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>d</b>) – czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, szósta litera alfabetu polskiego, w którym służy do oznaczania <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski zwartej dziąsłowej dźwięcznej</a>.", "Dobrowit": "<b>Dobrowit</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-wit</i> („pan, władca”). Oznacza „dobrego pana”, „dobrego władcę” albo „dobrze rządzącego”. Istnieje dokładny odpowiednik znaczeniowy tego imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_galijski\" target=\"_blank\" rel=\"noopener noreferrer\">języku galijskim</a>: <i>Suvallos</i>, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_praindoeuropejski\" target=\"_blank\" rel=\"noopener noreferrer\">prainoeurop.</a> elementem <i>su-</i> („dobrze, dobry”).", "Damin": "<b>Język damin</b> – <a href=\"https://pl.wikipedia.org/wiki/Rytua%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">rytualny</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> dwóch <a href=\"https://pl.wikipedia.org/wiki/Aborygeni_australijscy\" target=\"_blank\" rel=\"noopener noreferrer\">australijskich</a> <a href=\"https://pl.wikipedia.org/wiki/Plemi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">plemion</a>: Lardil i Yangkal, zamieszkałych na Wyspach Welseleya na <a href=\"https://pl.wikipedia.org/wiki/Zatoka_(geografia)\" target=\"_blank\" rel=\"noopener noreferrer\">zatoce</a> <a href=\"https://pl.wikipedia.org/wiki/Zatoka_Karpentaria\" target=\"_blank\" rel=\"noopener noreferrer\">Karpentaria</a> u wybrzeży <a href=\"https://pl.wikipedia.org/wiki/Stan_(podzia%C5%82_administracyjny)\" target=\"_blank\" rel=\"noopener noreferrer\">stanu</a> <a href=\"https://pl.wikipedia.org/wiki/Queensland\" target=\"_blank\" rel=\"noopener noreferrer\">Queensland</a> i mówiących spokrewnionymi językami należącymi do małej <a href=\"https://pl.wikipedia.org/wiki/Rodzina_j%C4%99zykowa\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny językowej</a> tangka (dosł. „osoba”). Samo słowo <i>damin</i> oznacza w lardil „bycie cicho”. Języka tego używano głównie podczas związanych z <a href=\"https://pl.wikipedia.org/wiki/Obrzezanie\" target=\"_blank\" rel=\"noopener noreferrer\">obrzezaniem</a> rytuałów luruku i warama — ostatnie z nich odbyły się w latach 50. XX w. — lecz niekiedy także w życiu codziennym. Obecnie jest znany jedynie grupce starców.", "Domarad": "<b>Domarad</b>, <b>Domorad</b>, <i><b>Domared(?)</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> (\"dom\"; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza \"pomieszczenie, gdzie człowiek żyje ze swoją rodziną\"; \"wszystko, co jest w domu, rodzina, mienie, majątek\", \"ród, pokolenie\", \"strony rodzinne, kraj ojczysty\") i <i>-rad</i> (\"radzić\" \"być zadowolonym, chętnym, cieszyć się\"). Mogło oznaczać \"ten, który cieszy się swoim domem\". We wczesnym średniowieczu synonim <a href=\"https://pl.wikipedia.org/wiki/Majordom\" target=\"_blank\" rel=\"noopener noreferrer\">Majordoma</a>, zarządcy dworu książęcego.", "Dzierżymir": "<b>Dzierżymir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>, nienotowane w źródłach staropolskich.", "Dina": "<b>Dina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa דִּינָה oznaczającego „sędzia”. Najbardziej znaną osobą o tym imieniu była biblijna <a href=\"https://pl.wikipedia.org/wiki/Dina_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Dina</a> córka <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lei</a>.", "Dory": "<b>Dory</b> – grecka nazwa <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włóczni</a> <i>dory</i>, <i>doru</i> pierwotnie oznaczała drzewo, bądź też odnosiła się do jego pnia. Włócznia była podstawowym orężem greckiego <a href=\"https://pl.wikipedia.org/wiki/Hoplici\" target=\"_blank\" rel=\"noopener noreferrer\">hoplity</a> (starożytni Grecy zwykli mówić o podbitym przez siebie terytorium iż zostało „włócznią zdobyte”). Były one wykonywane z drewna <a href=\"https://pl.wikipedia.org/wiki/Jesion\" target=\"_blank\" rel=\"noopener noreferrer\">jesionowego</a>, gdyż było jednocześnie lekkie i bardzo wytrzymałe. Ich długość sięgała 9 stóp (2,7 m.), a środek ciężkości znajdował się bliżej końca włóczni a nie na środku.", "Długosz": "<b>Długomił</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Długo-</i> (\"długi – rozciągnięty w przestrzeni\") i <i>-mił</i> (\"miły\"). Mogło ono oznaczać \"miły ludziom wszędzie na dużym obszarze\". Zdrobnieniem tego imienia jest Długosz.", "Deb": "<b>deb</b> – format <a href=\"https://pl.wikipedia.org/wiki/Pakiet_instalacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">pakietu instalacyjnego</a> używanego przez system operacyjny <a href=\"https://pl.wikipedia.org/wiki/Debian\" target=\"_blank\" rel=\"noopener noreferrer\">Debian GNU/Linux</a> – jedną z najstarszych, rozwijanych <a href=\"https://pl.wikipedia.org/wiki/Dystrybucja_Linuksa\" target=\"_blank\" rel=\"noopener noreferrer\">dystrybucji</a> <a href=\"https://pl.wikipedia.org/wiki/Linux\" target=\"_blank\" rel=\"noopener noreferrer\">Linuksa</a>. Wszystkie pakiety w tym formacie posiadają rozszerzenie .deb. Jest to skrót od „Deborah” (inaczej: „Debora”), imienia byłej żony twórcy Debiana, <a href=\"https://pl.wikipedia.org/wiki/Ian_Murdock\" target=\"_blank\" rel=\"noopener noreferrer\">Iana Murdocka</a>.", "Daba": "W jednym znaczeniu (wywodzonym z procesu <a href=\"https://pl.wikipedia.org/wiki/Synojkizm\" target=\"_blank\" rel=\"noopener noreferrer\">synojkizmu</a>) jest to kategoria <a href=\"https://pl.wikipedia.org/wiki/Podzia%C5%82_administracyjny\" target=\"_blank\" rel=\"noopener noreferrer\">podziału administracyjnego</a>, dla miejscowości zlokalizowanej w bezpośrednim sąsiedztwie <a href=\"https://pl.wikipedia.org/wiki/Brama_miejska\" target=\"_blank\" rel=\"noopener noreferrer\">bram miejskich</a> jakiegoś większego ośrodka. W drugim znaczeniu nazwa określa skupisko ludzi, które z powodu zagęszczenia <a href=\"https://pl.wikipedia.org/wiki/Demografia\" target=\"_blank\" rel=\"noopener noreferrer\">demograficznego</a> wewnątrz miasta, wychodzi poza <a href=\"https://pl.wikipedia.org/wiki/Fortyfikacja\" target=\"_blank\" rel=\"noopener noreferrer\">fortyfikacje</a> i gospodaruje na terenach do nich bezpośrednio przyległych.", "Diana": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dionizos": "Imię Dionizosa w formie dopełniaczowej (<i>di-wo-nu-so-jo</i>) pojawia się już w zapisanych <a href=\"https://pl.wikipedia.org/wiki/Pismo_linearne_B\" target=\"_blank\" rel=\"noopener noreferrer\">pismem linearnym B</a> zabytkach <a href=\"https://pl.wikipedia.org/wiki/Kultura_myke%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">mykeńskich</a> z XIV–XIII w. p.n.e. Ku czci tego boga odbywano uroczyste <a href=\"https://pl.wikipedia.org/wiki/Dionizje\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizje</a> i Oschoforia, a jego kult cechowały <a href=\"https://pl.wikipedia.org/wiki/Misteria_staro%C5%BCytne\" target=\"_blank\" rel=\"noopener noreferrer\">misteria</a> (<a href=\"https://pl.wikipedia.org/wiki/Misteria_eleuzyjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Eleuzynie</a>) oraz <a href=\"https://pl.wikipedia.org/wiki/Orgia\" target=\"_blank\" rel=\"noopener noreferrer\">orgiastyczne</a> obrzędy, w których uczestniczyły <a href=\"https://pl.wikipedia.org/wiki/Menady\" target=\"_blank\" rel=\"noopener noreferrer\">bachantki</a>.", "Denim": "Nazwa wywodzi się od francuskiego <i>bleu de Genes</i>, czyli „błękit genueński”, a nazwa <i>denim</i> pochodzi od francuskiego miasta <a href=\"https://pl.wikipedia.org/wiki/N%C3%AEmes\" target=\"_blank\" rel=\"noopener noreferrer\">Nîmes</a> (<i>de Nîmes</i> = z Nîmes). W obu tych miejscach już od XVI wieku wytwarzano tkaninę o takim splocie.", "Dargorad": "<b>Dargorad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Dargo-</i> (\"drogi\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\").", "Dacheng": "Populacja gminy Dacheng w 2016 roku liczyła 17&#160;284 mieszkańców – 7933 kobiety i 9351 mężczyzn. Liczba gospodarstw domowych wynosiła 5294, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,26 osób.", "Deli": "Deliler pochodzili głównie z <a href=\"https://pl.wikipedia.org/wiki/Rumelia\" target=\"_blank\" rel=\"noopener noreferrer\">Rumelii</a>, od żyjących tam Turków, Bośniaków, Chorwatów lub innych ludów słowiańskich. Formacja składała się z ochotników w wieku 20–25 lat, wyróżniających się odwagą. Ich patronem był drugi kalif <a href=\"https://pl.wikipedia.org/wiki/Umar_ibn_al-Chattab\" target=\"_blank\" rel=\"noopener noreferrer\">Umar</a>.", "Dewon": "<b>Dewon</b> – termin o dwojakim znaczeniu:", "Dydak": "<b>Dydak</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza „nauczający”, od gr. <i>διδαχή (didache)</i> (zob. też: <i><a href=\"https://pl.wikipedia.org/wiki/Dydaktyka\" target=\"_blank\" rel=\"noopener noreferrer\">dydaktyka</a></i>). Prawdopodobnie hiszpańskie imię <b>Diego</b>, od imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> (Santiago – Sanctus Iacobus; Diego, Diago) lub jako pochodzące z greki, ze słowa didax- 'doktryna, dyscyplina nauki'. Nie można też wykluczyć iberyjskiego (przedindoeuropejskiego) pochodzenia imienia. Patronem imienia jest św. Dydak, biskup <a href=\"https://pl.wikipedia.org/wiki/Kadyks\" target=\"_blank\" rel=\"noopener noreferrer\">Kadyksu</a>.", "Dek": "All hands on deck! (wszystkie ręce na pokład!) - to zawołanie żeglarskie oznaczające natychmiastowe wezwanie całej załogi na pokład w celu wykonania jakiejś czynności mającej ratować statek przed niebezpieczeństwem (np. w celu wykonania błyskawicznego manewru przed zauważoną właśnie górą lodową, lub zbliżającym się sztormem).", "Dobromysł": "<b>Dobromysł</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Dobro-</i> („dobry”) i <i>-mysł</i> („myśleć”, „myśl”). Mogło oznaczać „dobry w myśleniu”, lub ewentualnie „mający dobre myśli”. Imię <i>Dobromysl</i> występuje także w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_po%C5%82abski\" target=\"_blank\" rel=\"noopener noreferrer\">połabskim</a>. Istniał także odpowiednik znaczeniowy tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a>: <i>Su-mati-</i> („miej/mający dobrą myśl”, czyli „bądź mądry”); człon <i>su-</i> oznacza „dobrze, dobry”. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Danuta": "<b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Dewi": "<b>Dewi</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">devanagari</a>: देवी&#160;; „Bogini”), <b>Śri Devi</b> – imię, którym nazywane są często wszystkie bóstwa żeńskie panteonu <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistycznego</a>, jako różne aspekty tej samej bogini. Dewi często uważana jest za główne bóstwo na równi z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwą</a>. Jest bóstwem dobrotliwym jako <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, lub traktowana jest całkowicie niezależnie, a wówczas górę biorą jej groźniejsze aspekty w postaci <a href=\"https://pl.wikipedia.org/wiki/Durga\" target=\"_blank\" rel=\"noopener noreferrer\">Durgi</a> i <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a>.", "Džiugas": "<b>Džiugas</b> – <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewski</a> twardy <a href=\"https://pl.wikipedia.org/wiki/Ser\" target=\"_blank\" rel=\"noopener noreferrer\">ser</a> <a href=\"https://pl.wikipedia.org/wiki/Sery_podpuszczkowe\" target=\"_blank\" rel=\"noopener noreferrer\">podpuszczkowy</a>, jedyny twardy ser z Litwy, któremu <a href=\"https://pl.wikipedia.org/wiki/Komisja_Europejska\" target=\"_blank\" rel=\"noopener noreferrer\">Komisja Europejska</a> przyznała klasyfikację <a href=\"https://pl.wikipedia.org/wiki/Oznaczenia_pochodzenia_geograficznego_produkt%C3%B3w_rolnych_w_Unii_Europejskiej\" target=\"_blank\" rel=\"noopener noreferrer\">chronionego oznaczenia geograficznego</a>.", "Dedal": "Pochodził z <a href=\"https://pl.wikipedia.org/wiki/Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">Aten</a>, zbiegł jednak stamtąd po zamordowaniu swego siostrzeńca <a href=\"https://pl.wikipedia.org/wiki/Talos_(syn_Perdiks)\" target=\"_blank\" rel=\"noopener noreferrer\">Talosa</a>, któremu zazdrościł wynalezienia piły i koła garncarskiego. Schronił się na <a href=\"https://pl.wikipedia.org/wiki/Kreta\" target=\"_blank\" rel=\"noopener noreferrer\">Krecie</a>, gdzie pracował jako wynalazca na dworze króla <a href=\"https://pl.wikipedia.org/wiki/Minos\" target=\"_blank\" rel=\"noopener noreferrer\">Minosa</a>. Zbudował wtedy w <a href=\"https://pl.wikipedia.org/wiki/Knossos\" target=\"_blank\" rel=\"noopener noreferrer\">Knossos</a> <a href=\"https://pl.wikipedia.org/wiki/Labirynt\" target=\"_blank\" rel=\"noopener noreferrer\">labirynt</a>, pałac o skomplikowanym układzie korytarzy, w którym król zamknął <a href=\"https://pl.wikipedia.org/wiki/Minotaur\" target=\"_blank\" rel=\"noopener noreferrer\">Minotaura</a>. Gdy władca zabronił mu powrotu do ojczyzny i zamknął w labiryncie, Dedal wraz z synem uciekli na skrzydłach własnego pomysłu, wykonanych z piór zlepionych woskiem. W trakcie ucieczki Ikar zginął, gdy zanadto zbliżył się do słońca i rozgrzane jego żarem skrzydła uległy zniszczeniu. Po długich poszukiwaniach Dedal odnalazł szczątki syna na wyspie, którą na jego cześć nazwano <a href=\"https://pl.wikipedia.org/wiki/Ikaria\" target=\"_blank\" rel=\"noopener noreferrer\">Ikarią</a>, a morze, w którym zginął – <a href=\"https://pl.wikipedia.org/wiki/Morze_Ikaryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Ikaryjskim</a>.", "Dem": "Równolegle słowo to posiadało jeszcze dwa znaczenia.", "Degu": "Do laboratoriów <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a> koszatniczki trafiły w połowie lat 60. XX wieku, jako zwierzęta do prowadzenia badań nad <a href=\"https://pl.wikipedia.org/wiki/Cukrzyca\" target=\"_blank\" rel=\"noopener noreferrer\">cukrzycą</a>. <a href=\"https://pl.wikipedia.org/wiki/Insulina\" target=\"_blank\" rel=\"noopener noreferrer\">Insulina</a> tych gryzoni ma odmienną strukturę i wykazuje tylko 1–10% aktywności biologicznej w porównaniu z innymi ssakami, więc ich <a href=\"https://pl.wikipedia.org/wiki/Metabolizm\" target=\"_blank\" rel=\"noopener noreferrer\">metabolizm</a> nie pozwala na przyswajanie <a href=\"https://pl.wikipedia.org/wiki/Glukoza\" target=\"_blank\" rel=\"noopener noreferrer\">glukozy</a> i koszatniczki są bardzo podatne na tę chorobę. Osobniki pochodzące z populacji sprowadzonych jako zwierzęta laboratoryjne do laboratoriów w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">USA</a> i <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a> trafiły z czasem do indywidualnych hodowców hobbystycznych. W hodowli wymagają dużo wolnej przestrzeni. Powinny być hodowane w jednopłciowych parach lub stadach do 4–5 osobników.", "Domicjusz": "<b>Domicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od nazwy rodowej <i>Domicjuszy</i>, wywodzącej się od łac. <i>domitus</i>, co oznacza \"oswojony, poskromiony\". Istniało kilku świętych patronów tego imienia. Od <b>Domicjusza</b> pochodzi imię <a href=\"https://pl.wikipedia.org/wiki/Domicjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Domicjan</a>.", "Dionizjusz": "<b>Dionizjusz</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>.", "Domard": "<b>Domarad</b>, <b>Domorad</b>, <i><b>Domared(?)</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> (\"dom\"; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza \"pomieszczenie, gdzie człowiek żyje ze swoją rodziną\"; \"wszystko, co jest w domu, rodzina, mienie, majątek\", \"ród, pokolenie\", \"strony rodzinne, kraj ojczysty\") i <i>-rad</i> (\"radzić\" \"być zadowolonym, chętnym, cieszyć się\"). Mogło oznaczać \"ten, który cieszy się swoim domem\". We wczesnym średniowieczu synonim <a href=\"https://pl.wikipedia.org/wiki/Majordom\" target=\"_blank\" rel=\"noopener noreferrer\">Majordoma</a>, zarządcy dworu książęcego.", "Doda": "<b>Doda</b> – imię żeńskie pochodzenia germańskiego. Forma męska Dodo. W krajach anglosaskich jest skrótem od imienia <a href=\"https://pl.wikipedia.org/wiki/Dorota\" target=\"_blank\" rel=\"noopener noreferrer\">Dorota</a>.", "Dojin": "<b>Dōjin</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;同人&#32;<i>dōjin</i>&#44;&#32;dosł. „ci sami ludzie”) – japońskie słowo oznaczające koterię, klikę, grupę osób o zbliżonych celach lub zainteresowaniach. We współczesnej japońszczyźnie oznacza również grupę hobbystów i fanów publikujących własnym nakładem różne materiały, jak <a href=\"https://pl.wikipedia.org/wiki/Manga\" target=\"_blank\" rel=\"noopener noreferrer\">mangi</a>, powieści, poezję, albumy z fotografiami, muzykę i gry komputerowe. Część takich publikacji jest klasyfikowana jako <a href=\"https://pl.wikipedia.org/wiki/Fan_fiction\" target=\"_blank\" rel=\"noopener noreferrer\">fan fiction</a>, jednak grupy te publikują także prace oryginalne.", "Domasław": "<b>Domasław</b>, <b>Domisław</b>, <b>Domosław</b> – ogólnosłowiańskie, w tym staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni domowej.", "Dorota": "<b>Dorota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δωροθέα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δῶρον – dar i θεός – bóg, „dar od boga”). Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Doroteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Doroteusz</a>. W Polsce imię to odnotowano po raz pierwszy w 1385. Znane są też inne formy tego imienia: Dochna, Dora, Doroteja, Dorotka. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Teodora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Teodora</a> (a także imię <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a> pochodzenia hebrajskiego).", "Dagmara": "<b>Dagmara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Wywodzi się być może z połączenia słów <i>dag</i> „dzień” i <i>mar</i> „dziewica”, „panna”, albo też <i>mari</i> „sławny”. Możliwe, że jest to duńska wersja słowiańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomira\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomira</a>, które nosiła czeska księżniczka, żona <a href=\"https://pl.wikipedia.org/wiki/Waldemar_II_Zwyci%C4%99ski\" target=\"_blank\" rel=\"noopener noreferrer\">Waldemara II Zwycięskiego</a>. Brak jednoznacznego pochodzenia imienia. Może to być także żeńska forma imienia <b>Dagmar</b>, będącego imieniem dynastycznym u plemion frankońskich pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> oznaczająca 'wielki przez dobroć' lub <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> w znaczeniu 'mąż jasny jak dzień', jak i żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Dagobert\" target=\"_blank\" rel=\"noopener noreferrer\">Dagobert</a>.", "Daniela": "<b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Donata": "<b>Donata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Donat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Donat</a>. Łacińskie <i>donatus</i> oznacza „dany, darowany”. Wśród patronek tego imienia – św. Donata, jedna z wczesnych świętych Kościoła katolickiego.", "Dobrosława": "Najstarszy znany polski zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1200\" target=\"_blank\" rel=\"noopener noreferrer\">1200</a> roku&#8201;. Staropolskie zdrobnienia Dobrosławy: Dobrocha, Dobrochna (notowana od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku; obecnie bywa nadawana także samodzielnie), Dobroszka. Niektóre inne możliwe staropolskie zdrobnienia: Dobrosta, Dobrosza, Dobroszna, Dobruchna, Dobrusza, Dobruszka, Dochna&#8201;.", "Dalia": "<b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Dżesika": "<a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Dajana": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dobrawa": "<b>Dobrawa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Wywodzi się od słowa oznaczającego \"las dębowy\" (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">cz.</a>&#160;<em>doubrava</em> jest odpowiednikiem polskiej dąbrowy) lub od słowa oznaczającego „dosyć dobra, czasem dobra” (por. dobrawa, jak biaława, zimnawa itp) lub jest to skrót od złożonego imienia Dobrosława. Dwie ostatnie etymologie (zwłaszcza pierwszą z nich) potwierdza kronika <a href=\"https://pl.wikipedia.org/wiki/Thietmar_z_Merseburga\" target=\"_blank\" rel=\"noopener noreferrer\">Thietmara</a>, w której tłumaczy on to słowo jako „dobra”.", "Domicela": "<b>Domicela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (łac. <i>Domitilla</i>), utworzone od nazwy rodowej <i>Domicjuszów</i>. Pierwotnie oznaczało „pani domu”.", "Dobrochna": "Najstarszy znany polski zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1200\" target=\"_blank\" rel=\"noopener noreferrer\">1200</a> roku&#8201;. Staropolskie zdrobnienia Dobrosławy: Dobrocha, Dobrochna (notowana od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku; obecnie bywa nadawana także samodzielnie), Dobroszka. Niektóre inne możliwe staropolskie zdrobnienia: Dobrosta, Dobrosza, Dobroszna, Dobruchna, Dobrusza, Dobruszka, Dochna&#8201;.", "Dagna": "<b>Dagna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Spolszczona forma imienia <i>Dagny</i> wywodzącego się z połączenia słów <i>dag</i> – „dzień” i <i>ny</i> – „nowy”.", "Delfina": "<b>Delfina</b> — żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Delfin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Delfin</a>. Pojawiło się w Polsce dzięki wpływowi literatury dziewiętnastowiecznej, a jego pochodzenie objaśniane jest dwojako: z języka greckiego lub z języka francuskiego.", "Dobromiła": "<b>Dobromiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobro, dobra\") i <i>-miła</i> (\"miła\"). Mogło oznaczać \"ta, która jest dobra i miła\". W źródłach polskich poświadczone w XII wieku (lata 1185 – 1186).", "Debora": "<b>Debora</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דְּבוֹרָה&#8206;; żyła ok. <a href=\"https://pl.wikipedia.org/wiki/XII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">1200 p.n.e.</a>) – postać ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, żona Lappidota&#65279;<a href=\"https://www.wikidata.org/wiki/Q6488184#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, pochodząca z plemienia <a href=\"https://pl.wikipedia.org/wiki/Naftali_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Naftalego</a>.", "Dolores": "<b>Dolores</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hiszpańskiego wywodzące się od słowa <i>dolor</i> oznaczającego <i>ból</i>. W języku hiszpańskim używane w <i>María de los Dolores</i> – <a href=\"https://pl.wikipedia.org/wiki/Matka_Boska_Bolesna\" target=\"_blank\" rel=\"noopener noreferrer\">Matka Boska Bolesna</a>. Popularnym zdrobnieniem imienia Dolores jest Lola lub <a href=\"https://pl.wikipedia.org/wiki/Lolita_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lolita</a>.", "Dąbrówka": "<b>Dąbrówka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Tak nazywano <a href=\"https://pl.wikipedia.org/wiki/Dobrawa_Przemy%C5%9Blidka\" target=\"_blank\" rel=\"noopener noreferrer\">Dobrawę</a>, czeską żonę <a href=\"https://pl.wikipedia.org/wiki/Mieszko_I\" target=\"_blank\" rel=\"noopener noreferrer\">Mieszka I</a>. Imię pochodzi od <i>dąbrowy</i> – lasu dębowego. W źródłach polskich poświadczone od XII wieku jako Dąbrówka (XIII wiek), Dubrowka (1122 rok) i Dubrawka (1282 - 1286).", "Damiana": "<b>Damiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Damian</a>, pochodzenia greckiego.", "Dioniza": "<b>Dioniza</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>. Imię to pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>, od <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>, greckiego boga wina.", "Delia": "<b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "Dobromira": "<b>Dobromira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobry\") i <i>-mira</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, która ceni pokój\". W źródłach polskich poświadczone w XIII wieku.", "Dobiesława": "<b>Dobiesława</b>, <b>Dobosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobie-</i> (\"stosowna, zdatna\" albo \"waleczna, dzielna\") i <i>-sława</i> (\"sława\"). Po raz pierwszy odnotowane w dawnych dokumentach w <a href=\"https://pl.wikipedia.org/wiki/1284\" target=\"_blank\" rel=\"noopener noreferrer\">1284</a> roku. Imię to mogło oznaczać \"ciesząca się słuszną sławą\", \"słynąca z dzielności\" lub in. Niektóre możliwe staropolskie zdrobnienia: Dobachna, Dobala, Dobiechna, Dobka, Dochna.", "Damroka": "<b>Damroka</b> (Damroca, Dąbroca) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Czasami uznawane za wariant imienia: <a href=\"https://pl.wikipedia.org/wiki/D%C4%85br%C3%B3wka_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dąbrówka</a>. Występuje na <a href=\"https://pl.wikipedia.org/wiki/Pomorze_Nadwi%C5%9Bla%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Pomorzu Wschodnim</a> u <a href=\"https://pl.wikipedia.org/wiki/Kaszubi\" target=\"_blank\" rel=\"noopener noreferrer\">Kaszubów</a>.", "Dianna": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Danusia": "Producent tego wyrobu, którym była A. Piasecki-Fabryka Czekolady w Krakowie SA podawał, że tradycja jego produkcji sięga początków lat 20. XX wieku, kiedy ówczesny właściciel fabryki <a href=\"https://pl.wikipedia.org/wiki/Adam_Piasecki_(przemys%C5%82owiec)\" target=\"_blank\" rel=\"noopener noreferrer\">Adam Piasecki</a> zakochał się w swojej pracownicy o imieniu <a href=\"https://pl.wikipedia.org/wiki/Danuta\" target=\"_blank\" rel=\"noopener noreferrer\">Danuta</a>. To dla niej miał wymyślić recepturę batonika, nazwać produkt jej imieniem i umieścić jej podobiznę na opakowaniu.", "Debra": "<b>Debrza</b> lub <b>debra</b> – forma ukształtowania powierzchni ziemi: wąska, płytka, <a href=\"https://pl.wikipedia.org/wiki/Dolina_V-kszta%C5%82tna\" target=\"_blank\" rel=\"noopener noreferrer\">V-kształtna dolina</a> <a href=\"https://pl.wikipedia.org/wiki/Dolina_sucha\" target=\"_blank\" rel=\"noopener noreferrer\">sucha</a> o znacznym i niewyrównanym spadku.", "Dahlia": "<b>Dalia</b>, georginia (<i>Dahlia</i> Cav.) – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_nasienne\" target=\"_blank\" rel=\"noopener noreferrer\">roślin nasiennych</a> należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Astrowate\" target=\"_blank\" rel=\"noopener noreferrer\">astrowatych</a>. Obejmuje 41 gatunków. Występują one w <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Centralna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryce Centralnej</a> (od <a href=\"https://pl.wikipedia.org/wiki/Meksyk\" target=\"_blank\" rel=\"noopener noreferrer\">Meksyku</a> po <a href=\"https://pl.wikipedia.org/wiki/Panama\" target=\"_blank\" rel=\"noopener noreferrer\">Panamę</a>) oraz w <a href=\"https://pl.wikipedia.org/wiki/Kolumbia\" target=\"_blank\" rel=\"noopener noreferrer\">Kolumbii</a>, przy czym najbardziej zróżnicowane są w Meksyku. Rosną głównie na obszarach górskich, zarówno w formacjach leśnych, jak i nieleśnych.", "Daina": "<b>Daina</b> – tradycyjna forma nierymowanej pieśni łotewskiej i litewskiej, najczęściej bardzo krótkiej (do czterech strof), zróżnicowanej pod względem tematyki, metryki, stylistyki i sposobu wykonywania.", "Domnika": "Urodzony w 366 jedyny syn Domniki i Walensa otrzymał na cześć stryja imię Walentynian. Od miejsca urodzenia (<a href=\"https://pl.wikipedia.org/wiki/Galacja\" target=\"_blank\" rel=\"noopener noreferrer\">Galacji</a> w Azji Mniejszej) nadano mu przydomek Galates. Jako trzyletni został konsulem, lecz ok. 370 zachorował i zmarł. Cesarska para miała również dwie córki, Anastazję i Karosę, których wychowanie powierzono kapłanowi Marcjanowi, należącemu do purystycznego odłamu <a href=\"https://pl.wikipedia.org/wiki/Nowacjanizm\" target=\"_blank\" rel=\"noopener noreferrer\">nowacjan</a>.", "Dionizja": "<b>Dionizja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>.", "Dobrogniewa": "<b>Dobrogniewa</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobra\") oraz <i>-gniewa</i> (\"gniew\"). Mogło oznaczać \"ta, której gniew jest zawsze dobry\" lub in.", "Drogosława": "<b>Drogosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> („drogi”) i <i>-sława</i> („sława”). Mogło ono oznaczać „ta, której droga jest sława”. W źródłach polskich poświadczone w XIV wieku (1400 rok).", "Domna": "<b>Domna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, notowane w Polsce już od <a href=\"https://pl.wikipedia.org/wiki/1438\" target=\"_blank\" rel=\"noopener noreferrer\">1438</a> roku, wywodzące się od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Domna</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celt.</a> <i>Domnus</i>, <i>Donnus</i> lub łac. <i>Dominus</i> (\"Pan\").", "Dzierżysława": "<b>Dzirżysława</b>, <b>Dziersława</b>, <b>Dzirsława</b>, <b>Dzierżysława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dzirży-</i> („trzymać”) i <i>-sława</i> („sława”). Oznaczało prawdopodobnie „tę, która posiada sławę”. W źródłach polskich poświadczone jako Dzirżysława (XII wiek), Dziersława (1400 rok).", "Darosława": "<b>Darosława</b> – żeńska odmiana <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Darosław</a>.", "Demetria": "<b>Demetria</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Demetriusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Demetriusz</a>. Znaczy \"należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>\".", "Drogomira": "<b>Drogomira</b>, <b>Drogmira</b>, <b>Dragomira</b>, <b>Drahomira</b>, <b>Drohomira</b>, <b>Dargomiera</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, której drogi jest pokój\". Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomir\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomir</a> i podobnych.", "Dipa": "<b>Dipa</b>, ang. deepa, z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> दीप <i>dīpa</i>, dosłownie <a href=\"https://pl.wikipedia.org/wiki/Lampa\" target=\"_blank\" rel=\"noopener noreferrer\">lampa</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/Hindi\" target=\"_blank\" rel=\"noopener noreferrer\">hindi</a> określana również jako दिया <i>dija</i>, दीप <i>dip</i>, दीपक <i>dipak</i>, दीवा <i>diwa</i>. Choć etymologicznie wszystkie terminy oznaczają to samo, współcześnie rozróżnia się zazwyczaj jednorazowe lampki <a href=\"https://pl.wikipedia.org/wiki/Glina\" target=\"_blank\" rel=\"noopener noreferrer\">gliniane</a>, oraz lampki <a href=\"https://pl.wikipedia.org/wiki/Mosi%C4%85dz\" target=\"_blank\" rel=\"noopener noreferrer\">mosiężne</a>, używane na stałe w <a href=\"https://pl.wikipedia.org/wiki/Dom\" target=\"_blank\" rel=\"noopener noreferrer\">domu</a> lub <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%85tynia\" target=\"_blank\" rel=\"noopener noreferrer\">świątyni</a>. Oba rodzaje to najczęściej małe lampki oliwne, sławne dzięki wielkiemu \"Świętu Światła\", zwanemu <a href=\"https://pl.wikipedia.org/wiki/Diwali\" target=\"_blank\" rel=\"noopener noreferrer\">Diwali</a> lub <i>Dipawali</i>. Stosuje się najczęściej <a href=\"https://pl.wikipedia.org/wiki/Ghi\" target=\"_blank\" rel=\"noopener noreferrer\">ghi</a> lub <a href=\"https://pl.wikipedia.org/wiki/Oleje_ro%C5%9Blinne\" target=\"_blank\" rel=\"noopener noreferrer\">olej roślinny</a>.", "Dezyderia": "<b>Dezyderia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dezydery\" target=\"_blank\" rel=\"noopener noreferrer\">Dezydery</a>. Oznacza \"upragniona\".", "Dawida": "<b>Dawida</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dawid_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawid</a>.", "Dobroniega": "<b>Dobroniega</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Dobro-</i> (\"dobra\") i <i>-niega</i> (\"rozkosz\"). Mogło zatem oznaczać \"ta, która dostarcza przyjemnosci, rozkoszy\".", "Domosława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Dafina": "<b>Dafina Zeqiri</b>, znana także jako <b>Dafina</b> oraz <b>Duffye</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/14_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">14 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1989\" target=\"_blank\" rel=\"noopener noreferrer\">1989</a> w <a href=\"https://pl.wikipedia.org/wiki/Varberg\" target=\"_blank\" rel=\"noopener noreferrer\">Varberg</a>) – szwedzka piosenkarka pochodzenia kosowsko–albańskiego, związana z gatunkami <a href=\"https://pl.wikipedia.org/wiki/Muzyka_pop\" target=\"_blank\" rel=\"noopener noreferrer\">pop</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">rhythm and blues</a>.", "Domasława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Dalebora": "<b>Dalebora</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dale-</i> (\"daleko\", może też \"oddalać\") i <i>-bora</i> (\"walka\"). Oznaczałoby więc \"tę, która pozostaje daleko od walki\".", "Doma": "<b>Domowie</b> lub <b>Doma</b> (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_domari\" target=\"_blank\" rel=\"noopener noreferrer\">języku domari</a> dosłownie „ludzie”) – <a href=\"https://pl.wikipedia.org/wiki/Grupa_etniczna\" target=\"_blank\" rel=\"noopener noreferrer\">grupa etniczna</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Indusi\" target=\"_blank\" rel=\"noopener noreferrer\">indyjskiego</a> zamieszkująca kraje <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskiego Wschodu</a>. Są blisko spokrewnieni z <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">europejskimi</a> <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">Romami</a>, <a href=\"https://pl.wikipedia.org/wiki/Azja_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">środkowoazjatyckimi</a> Luli, <a href=\"https://pl.wikipedia.org/wiki/Lomowie\" target=\"_blank\" rel=\"noopener noreferrer\">Lomami</a> z <a href=\"https://pl.wikipedia.org/wiki/Armenia\" target=\"_blank\" rel=\"noopener noreferrer\">Armenii</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjską</a> <a href=\"https://pl.wikipedia.org/wiki/Kasta\" target=\"_blank\" rel=\"noopener noreferrer\">kastą</a> Domba. Wszystkie te grupy są często traktowane łącznie jako <a href=\"https://pl.wikipedia.org/wiki/Cyganie\" target=\"_blank\" rel=\"noopener noreferrer\">Cyganie</a>. Domowie mają bogatą kulturę opartą na muzyce, tańcu oraz tradycji ustnej.", "Drahomira": "Po śmierci Ludmiły Drahomira doprowadziła do wygnania księży. Choć niewątpliwie była zwolenniczką pogaństwa (na co wskazuje nie tylko jej pochodzenie, lecz choćby preferowany przez nią sposób wychowania synów), spotkać się można z opinią, że istotnym powodem tych wydarzeń był przede wszystkim sprzeciw Drahomiry wobec polityczno-kościelnego zwierzchnictwa <a href=\"https://pl.wikipedia.org/wiki/Bawaria\" target=\"_blank\" rel=\"noopener noreferrer\">Bawarii</a>.", "Dobrosułka": "<b>Dobrosułka</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Dobro-</i> (\"dobry\") i <i>-sułka</i> (\"obiecywać\" albo \"lepsza, możniejsza\"). Może oznaczać \"obiecująca dobro\".", "Dragomira": "<b>Drogomira</b>, <b>Drogmira</b>, <b>Dragomira</b>, <b>Drahomira</b>, <b>Drohomira</b>, <b>Dargomiera</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, której drogi jest pokój\". Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomir\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomir</a> i podobnych.", "Dżina": "<b>Wardhamana Mahawira</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>&#160;वर्धमान <i>vardhamāna</i> – \"wzrastający\", to jego imię własne; महावीर <i>mahāvīra</i> – \"wielki bohater\", to tytuł, pod jakim go czczą wyznawcy) – pierwszy zaświadczony historycznie przywódca dżinijski, uważany powszechnie za założyciela <a href=\"https://pl.wikipedia.org/wiki/D%C5%BAinizm\" target=\"_blank\" rel=\"noopener noreferrer\">dźinizmu</a>; według tradycji ostatni, dwudziesty czwarty z <a href=\"https://pl.wikipedia.org/wiki/Tirthankara\" target=\"_blank\" rel=\"noopener noreferrer\">tirthankarów</a>. Nazywa się go także przydomkiem <b>Dżina</b> (sanskr. <i>jina</i> – \"zwycięzca\").", "Domisława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Dada": "Znaczenie dadaistów polegało na przesunięciu granic sztuki i umożliwieniu artystom swobody wypowiedzi. Odegrali także rolę w odrzuceniu tradycyjnie pojmowanej sztuki i estetyki, za dzieła uznając przedmioty codziennego użytku, wytwory przypadku czy wręcz śmieci. Na ruinach dadaizmu wyrósł <a href=\"https://pl.wikipedia.org/wiki/Surrealizm\" target=\"_blank\" rel=\"noopener noreferrer\">surrealizm</a>, po części tworzony przez tych samych artystów.", "Dema": "<b>DEMA</b> jest skrótem oznaczającym <i>Double Exponential Moving Average</i>. Jednakże, nazwa tej techniki gładzenia jest trochę myląca, ponieważ nie jest to prosta <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednia_ruchoma\" target=\"_blank\" rel=\"noopener noreferrer\">średnia ruchoma</a> średniej ruchomej. DEMA zawiera wyjątkową w swoim rodzaju mieszaniną pojedynczej wykładniczej średniej ruchomej i podwójnej wykładniczej średniej ruchomej, co powoduje mniej pomyłek, niż każdy z tych dwóch składników z osobna.", "Doryda": "<b>Doryda</b> – spolszczenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Doris</i>, znanego z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Imię to oznaczało kobietą pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Doryda_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Doris</a>, krainy w środkowej <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>.", "Dejanira": "Później małżonkowie opuścili Kalydon. Wędrowali razem, poszukując miejsca dogodnego do osiedlenia się. Herakles często niósł Dejanirę, by oszczędzić jej trudu, przenosił ją też przez strumienie. Pewnego razu jednak nad strumieniem spotkali <a href=\"https://pl.wikipedia.org/wiki/Centaury_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">centaura</a> imieniem <a href=\"https://pl.wikipedia.org/wiki/Nessos\" target=\"_blank\" rel=\"noopener noreferrer\">Nessos</a>. Zaproponował on, że przewiezie Dejanirę przez strumień na swym końskim grzbiecie. Gdy jednak znalazł się z królewną ledwie kilka kroków od potężnego herosa, zdradliwie porwał niewiastę, rzucając się z nią do ucieczki i próbując <a href=\"https://pl.wikipedia.org/wiki/Gwa%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">zgwałcić</a>. Herakles nie pozwolił mu zabrać swej kobiety. Strzelił z <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuku</a> do porywacza, śmiertelnie go raniąc. Nessos przed zgonem zdołał jeszcze przemówić do swej ofiary. Poinformował mianowicie Dejanirę o niezwykłych własnościach jego krwi: przedstawił ją jako cudowny wręcz środek miłosny, mogący zapewnić niewieście na zawsze miłość męża. Dejanira zebrała do flakonika porcję krwi centaura, schowała go i, ponaglana przez Heraklesa, dołączyła do niego. Udali się do Trachis, przyjęci przez władcę Keyksa. Pokonali razem Dryopów.", "Dzisława": "<b>Dziesława</b>, <b>Dzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dzie-</i> (\"położyć, postawić\"; \"zrobić, uczynić\"; także \"rzec, powiedzieć\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"ta, która buduje sławę\".", "Dafroza": "<b>Dafroza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Pas\" target=\"_blank\" rel=\"noopener noreferrer\">pas</a> ozdobiony <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">różami</a>”. Patronką tego imienia jest św. Dafroza, <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BConkowie\" target=\"_blank\" rel=\"noopener noreferrer\">żona</a> św. <a href=\"https://pl.wikipedia.org/wiki/Flawian\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiana</a> i <a href=\"https://pl.wikipedia.org/wiki/Rodzice\" target=\"_blank\" rel=\"noopener noreferrer\">matka</a> św. <a href=\"https://pl.wikipedia.org/wiki/Bibiana\" target=\"_blank\" rel=\"noopener noreferrer\">Bibiany</a> (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Deianira": "Później małżonkowie opuścili Kalydon. Wędrowali razem, poszukując miejsca dogodnego do osiedlenia się. Herakles często niósł Dejanirę, by oszczędzić jej trudu, przenosił ją też przez strumienie. Pewnego razu jednak nad strumieniem spotkali <a href=\"https://pl.wikipedia.org/wiki/Centaury_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">centaura</a> imieniem <a href=\"https://pl.wikipedia.org/wiki/Nessos\" target=\"_blank\" rel=\"noopener noreferrer\">Nessos</a>. Zaproponował on, że przewiezie Dejanirę przez strumień na swym końskim grzbiecie. Gdy jednak znalazł się z królewną ledwie kilka kroków od potężnego herosa, zdradliwie porwał niewiastę, rzucając się z nią do ucieczki i próbując <a href=\"https://pl.wikipedia.org/wiki/Gwa%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">zgwałcić</a>. Herakles nie pozwolił mu zabrać swej kobiety. Strzelił z <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuku</a> do porywacza, śmiertelnie go raniąc. Nessos przed zgonem zdołał jeszcze przemówić do swej ofiary. Poinformował mianowicie Dejanirę o niezwykłych własnościach jego krwi: przedstawił ją jako cudowny wręcz środek miłosny, mogący zapewnić niewieście na zawsze miłość męża. Dejanira zebrała do flakonika porcję krwi centaura, schowała go i, ponaglana przez Heraklesa, dołączyła do niego. Udali się do Trachis, przyjęci przez władcę Keyksa. Pokonali razem Dryopów.", "Dula": "<b>Dula</b> – żeński odpowiednik imienia Dulas, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, oznaczające \"bliźniaczka\". W średniowiecznej Polsce, w <a href=\"https://pl.wikipedia.org/wiki/1497\" target=\"_blank\" rel=\"noopener noreferrer\">1497</a> r. została odnotowana ta nazwa osobowa, jednak w tym przypadku o niepewnej etymologii (może od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*dulěti</i> – \"stawać się tłustym\" lub <i>gdula</i>, prasł. <i>kъdulja</i> – \"rodzaj gruszek\"), z formami pochodnymi <i>Dul</i>, <i>Dulaj</i>, <i>Dulak</i>, <i>Dulek</i>, <i>Dulka</i>, <i>Dulna</i>.", "Diodora": "<b>Diodora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>Διοδωρος (Diodoros)</i>, co oznacza „dar <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>” („dar Boga”). Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Diodor\" target=\"_blank\" rel=\"noopener noreferrer\">Diodor</a>. Wśród patronów — św. Diodor, wspominany razem ze św. Rodopianem.", "Dell": "<b>Dell Technologies Inc.</b> (wcześniej <b>Dell Inc.</b> i <b>Dell Computer Corporation</b>) – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskie</a> przedsiębiorstwo z siedzibą w <a href=\"https://pl.wikipedia.org/wiki/Round_Rock_(Teksas)\" target=\"_blank\" rel=\"noopener noreferrer\">Round Rock</a> w stanie <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksas</a>, które opracowuje, sprzedaje, naprawia i obsługuje <a href=\"https://pl.wikipedia.org/wiki/Komputer\" target=\"_blank\" rel=\"noopener noreferrer\">komputery</a> oraz powiązane produkty i usługi. Nazwa pochodzi od nazwiska założyciela firmy <a href=\"https://pl.wikipedia.org/wiki/Michael_Dell\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Della</a> i jest jednym z największych przedsiębiorstw technologicznych na świecie, zatrudniającą ponad 97 000 osób w różnych krajach.", "Deka": "<b>Deka</b> (<b>da</b>) (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr</a>. <i>δέκα</i> [deka] oznaczającego <i>dziesięć</i>) – <a href=\"https://pl.wikipedia.org/wiki/Przedrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przedrostek</a> <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki miary</a> oznaczający <a href=\"https://pl.wikipedia.org/wiki/Mno%C5%BCenie\" target=\"_blank\" rel=\"noopener noreferrer\">mnożnik</a> 10 = 10. Przed wprowadzeniem w Polsce <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układu SI</a> w 1966 roku funkcjonował skrót <i>dk</i>. Przedrostek ten (podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Decy\" target=\"_blank\" rel=\"noopener noreferrer\">decy</a>) jest stosowany dość rzadko w porównaniu z niektórymi innymi przedrostkami jednostek miary. Przykładowo, używany jest wraz z <a href=\"https://pl.wikipedia.org/wiki/Niuton\" target=\"_blank\" rel=\"noopener noreferrer\">niutonem</a> jako daN do oznaczania ciężaru z przyczyn praktycznych, bowiem 1 daN odpowiada w przybliżeniu 1 kG (<a href=\"https://pl.wikipedia.org/wiki/Kilogram-si%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">kilogram-siła</a>).", "Dziuba": "<b>Dziuba</b> – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie</a>, białoruskie, ukraińskie i rosyjskie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiły je 8972 osoby, według nowszych, internetowych danych nosi je 8129 osób. Nazwisko pochodzi od słów <i><a href=\"https://pl.wiktionary.org/wiki/dzi%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">dziób</a></i> lub <i><a href=\"https://pl.wiktionary.org/wiki/dzioba%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dziobać</a></i> i jest najbardziej rozpowszechnione w południowo-środkowej i południowo-wschodniej Polsce."};
